update tms_student as s
join tms_machine_type as mt on mt.machine_type_id = #{primaryMachineTypeId}
set s.primary_machine_type_name = mt.machine_type_name
where s.student_id = #{studentId}

update tms_student as s
join tms_major as m on m.major_id = #{primaryMajorId}
set s.primary_major_name = m.major_name
where s.student_id = #{studentId}
